namespace sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels = new()
        {
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering topics and code reviews", 0),
            new(3, "design", "Design discussions and feedback", 1),
            new(4, "random", "Off-topic fun and water cooler chat", 5),
            new(5, "announcements", "Important team announcements", 0),
        };

        var now = DateTime.UtcNow;
        _messages = new()
        {
            new(1, 1, "Alice", "Hey team! Has anyone looked at the new API spec?", now.AddHours(-3), null,
                new() { new("👍", new() { "Bob", "Carol" }), new("👀", new() { "Dave" }) }),
            new(2, 1, "Bob", "Yes, I reviewed it yesterday. Looks solid overall.", now.AddHours(-2.5), null, new()),
            new(3, 1, "Carol", "I have some questions about the auth flow. Can we discuss?", now.AddHours(-2), null,
                new() { new("💬", new() { "Alice" }) }),
            new(4, 1, "Dave", "Sure, let's set up a quick call this afternoon.", now.AddMinutes(-90), null, new()),
            new(5, 1, "Alice", "Sounds good! I'll send a calendar invite.", now.AddMinutes(-45), null,
                new() { new("🎉", new() { "Bob", "Carol", "Dave" }) }),
            new(6, 1, "Bob", "Great, looking forward to it.", now.AddMinutes(-30), null, new()),
            new(7, 1, "Carol", "Same here. I'll prepare my questions.", now.AddMinutes(-15), null, new()),
            new(8, 1, "Dave", "Don't forget to check the updated docs too.", now.AddMinutes(-5), null, new()),

            // Thread replies for message 1
            new(10, 1, "Bob", "The pagination section is really well done.", now.AddHours(-2.4), 1, new()),
            new(11, 1, "Carol", "Agreed. Though I'd prefer cursor-based pagination.", now.AddHours(-2.2), 1, new()),
            new(12, 1, "Alice", "Good point Carol, I'll bring that up.", now.AddHours(-2), 1, new()),

            // Thread replies for message 3
            new(13, 1, "Alice", "Happy to walk you through it.", now.AddHours(-1.8), 3, new()),
            new(14, 1, "Carol", "Thanks! Mainly about the refresh token rotation.", now.AddHours(-1.5), 3, new()),

            new(20, 2, "Dave", "Just merged the refactor PR. Please pull latest.", now.AddHours(-1), null,
                new() { new("🚀", new() { "Alice", "Bob" }) }),
            new(21, 2, "Alice", "On it! Any breaking changes?", now.AddMinutes(-50), null, new()),
            new(22, 2, "Dave", "None. All tests pass.", now.AddMinutes(-40), null,
                new() { new("✅", new() { "Alice" }) }),
        };
    }

    public Task<List<Channel>> GetChannelsAsync()
        => Task.FromResult(_channels.Select(c => c with { }).ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var msgs = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(msgs);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(
            _nextMessageId++, channelId, "You", content,
            DateTime.UtcNow, replyToId, new());
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (root == null) return Task.FromResult(new List<Message>());

        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();

        var result = new List<Message> { root };
        result.AddRange(replies);
        return Task.FromResult(result);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg != null)
        {
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing != null)
            {
                reactions.Remove(existing);
                var users = existing.Users.ToList();
                if (!users.Contains("You")) users.Add("You");
                reactions.Add(new Reaction(emoji, users));
            }
            else
            {
                reactions.Add(new Reaction(emoji, new() { "You" }));
            }

            var index = _messages.IndexOf(msg);
            _messages[index] = msg with { Reactions = reactions };
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var ch = _channels.FirstOrDefault(c => c.Id == channelId);
        if (ch != null)
        {
            var index = _channels.IndexOf(ch);
            _channels[index] = ch with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}

