@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services

<div class="message-item" @onmouseenter="() => _hovered = true" @onmouseleave="() => { _hovered = false; _showEmojiPicker = false; }">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ShowThreadLink && ReplyCount > 0)
    {
        <button class="thread-link" @onclick="HandleOpenThread">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered && ShowActions)
    {
        <div class="action-bar">
            <button class="action-btn" @onclick="HandleOpenThread" title="Reply in thread">💬 Reply</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀 React</button>
        </div>

        @if (_showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in _commonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => HandleReact(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool ShowActions { get; set; } = true;
    [Parameter] public bool ShowThreadLink { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private static readonly string[] _commonEmojis = { "👍", "❤️", "😂", "🎉", "🚀", "👀" };

    private async Task HandleOpenThread() => await OnOpenThread.InvokeAsync(Message.Id);

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleReact(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

