.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 6px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.93rem;
    color: #1a1a2e;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.92rem;
    color: #333;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #f0f0f5;
    border: 1px solid #e0e0e8;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: default;
}

.thread-link {
    background: none;
    border: none;
    color: #4a6cf7;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -12px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    padding: 2px;
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 10px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f5;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 170px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    padding: 4px;
    z-index: 11;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f5;
}

