arguments.file_text:
@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>💬 Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #1e1e2e;
    color: #e0e0e0;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 12px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 6px 0;
}

@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services

<div class="message-area">
    @if (CurrentChannel is not null)
    {
        <div class="area-header">
            <h2># @CurrentChannel.Name</h2>
            <span class="area-desc">@CurrentChannel.Description</span>
        </div>

        <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
            @if (IsLoadingMore)
            {
                <div class="loading-more">Loading older messages…</div>
            }
            @foreach (var msg in Messages)
            {
                var thread = ThreadSummaries.GetValueOrDefault(msg.Id);
                <MessageItem Message="msg"
                             ShowThreadLink="true"
                             ReplyCount="@(thread?.ReplyCount ?? 0)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{CurrentChannel.Name}")"
                      ButtonText="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;

    private async Task HandleScroll()
    {
        // We use JS interop-free approach: trigger load-more via a button or detect
        // scroll position. For simplicity, we check on scroll events.
        // In a real app, you'd use JS interop to detect scrollTop === 0.
        await OnLoadMore.InvokeAsync();
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8ec;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #1a1a2e;
}

.area-desc {
    font-size: 0.82rem;
    color: #777;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-more {
    text-align: center;
    padding: 10px;
    font-size: 0.85rem;
    color: #999;
}

.no-channel {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1.1rem;
}

@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage" ShowActions="false" />
        </div>

        <div class="thread-replies">
            @if (ThreadMessages.Count > 1)
            {
                <div class="reply-divider">
                    <span>@(ThreadMessages.Count - 1) @(ThreadMessages.Count - 1 == 1 ? "reply" : "replies")</span>
                </div>
            }
            @foreach (var reply in ThreadMessages.Where(m => m.Id != RootMessage.Id))
            {
                <MessageItem Message="reply" ShowActions="false" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    }
</div>

@code {
