@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage" ShowActions="false" />
        </div>

        <div class="thread-replies">
            @if (ThreadMessages.Count > 1)
            {
                <div class="reply-divider">
                    <span>@(ThreadMessages.Count - 1) @(ThreadMessages.Count - 1 == 1 ? "reply" : "replies")</span>
                </div>
            }
            @foreach (var reply in ThreadMessages.Where(m => m.Id != RootMessage.Id))
            {
                <MessageItem Message="reply" ShowActions="false" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fafafe;
    border-left: 1px solid #e0e0e8;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e8e8ec;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
    color: #1a1a2e;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    color: #999;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: #eee;
    color: #333;
}

.thread-root {
    border-bottom: 1px solid #e8e8ec;
    background: #f5f5fa;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.reply-divider {
    display: flex;
    align-items: center;
    padding: 8px 16px;
    gap: 12px;
}

.reply-divider::before,
.reply-divider::after {
    content: "";
    flex: 1;
    height: 1px;
    background: #ddd;
}

.reply-divider span {
    font-size: 0.78rem;
    color: #999;
    white-space: nowrap;
}

