arguments.file_text:
@inherits LayoutComponentBase

<div class="chat-layout">
    @Body
</div>

.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    margin: 0;
    padding: 0;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Components.Chat
@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Components.Layout
@using sv_dc7dd10bb1cb41ccb1852a3940cd39fb.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="HandleChannelSelected" />
    </div>

    <div class="main-panel @(_isThreadOpen ? "" : "expanded")">
        <MessageArea Messages="_messages"
                     CurrentChannel="_currentChannel"
                     ThreadSummaries="_threadSummaries"
                     IsLoadingMore="_isLoadingMore"
                     OnOpenThread="HandleOpenThread"
                     OnReact="HandleReact"
                     OnSendMessage="HandleSendMessage"
                     OnLoadMore="HandleLoadMore" />
    </div>

    @if (_isThreadOpen)
    {
        <div class="thread-panel">
            <ThreadPanel RootMessage="_threadRootMessage"
                         ThreadMessages="_threadMessages"
                         OnClose="HandleCloseThread"
                         OnSendReply="HandleSendReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = new();
    private List<Message> _messages = new();
    private Channel? _currentChannel;
    private int? _selectedChannelId;
    private const int PageSize = 50;

    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = new();
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _currentChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _hasMoreMessages = true;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();

        await BuildThreadSummaries();
    }

    private async Task HandleChannelSelected(int channelId)
    {
        _isThreadOpen = false;
        _threadMessages.Clear();
        _threadRootMessage = null;
        await SelectChannel(channelId);
    }

    private async Task HandleSendMessage(string content)
    {
        if (_selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task HandleOpenThread(int messageId)
    {
        _threadMessages = await ChatService.GetThreadAsync(messageId);
        _threadRootMessage = _threadMessages.FirstOrDefault();
        _isThreadOpen = _threadRootMessage is not null;
    }

    private async Task HandleCloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages.Clear();
        await Task.CompletedTask;
    }

    private async Task HandleSendReply(string content)
    {
        if (_threadRootMessage is null || _selectedChannelId is null) return;
        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);
        await BuildThreadSummaries();
    }

    private async Task HandleReact((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        if (_selectedChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(
                _selectedChannelId.Value, 0, _messages.Count);
        }

        if (_isThreadOpen && _threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private async Task HandleLoadMore()
    {
        if (_isLoadingMore || !_hasMoreMessages || _selectedChannelId is null) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(
            _selectedChannelId.Value, _messages.Count, PageSize);

        if (older.Count == 0)
        {
            _hasMoreMessages = false;
        }
        else
        {
            _messages.InsertRange(0, older);
        }
        _isLoadingMore = false;
    }

    private async Task BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        foreach (var msg in _messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var replies = thread.Where(m => m.ReplyToId == msg.Id).ToList();
            if (replies.Count > 0)
            {
                _threadSummaries[msg.Id] = new ThreadSummary(
                    msg.Id, replies.Count, replies.Max(r => r.SentAt));
            }
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.sidebar-panel {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-panel {
    flex: 1;
    min-width: 0;
}

.main-panel.expanded {
    flex: 1;
}

.thread-panel {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

